mapper.update:
UPDATE ip_proxy
SET status = #{usingStatus},
    bound_account_id = #{accountId},
    bound_at = #{boundAt},
    updated_at = #{boundAt}
WHERE id = #{id}
  AND deleted_at IS NULL
  AND status = #{idleStatus}

UPDATE ip_proxy
SET status = #{idleStatus},
    bound_account_id = NULL,
    bound_at = NULL,
    updated_at = #{updatedAt}
WHERE bound_account_id = #{accountId}
  AND deleted_at IS NULL
  AND status = #{usingStatus}

